const body = $input.first().json.body || {};
const sourceCreatedAt = body.source_created_at || body.sourceCreatedAt || body.created_at || body.createdAt || body.timestamp || new Date().toISOString();
const userChatId = String(body.user_chat_id || body.userChatId || '');
const sourceChannel = String(body.source_channel || body.sourceChannel || body.channel || 'telegram-flora');
const sourceMessageId = String(
  body.source_message_id ||
  body.sourceMessageId ||
  body.telegram_message_id ||
  body.telegramMessageId ||
  body.message_id ||
  body.messageId ||
  body.request_id ||
  body.requestId ||
  `${userChatId || 'unknown'}:${sourceCreatedAt}`
);

return [{
  json: {
    sourceChannel,
    sourceMessageId,
    userChatId,
    userName: String(body.user_name || body.userName || ''),
    agentId: String(body.agent_id || body.agentId || 'owner'),
    messageText: String(body.message_text || body.messageText || ''),
    responseSummary: String(body.response_summary || body.responseSummary || ''),
    modelUsed: String(body.model_used || body.modelUsed || 'gpt-5.4'),
    skillTriggered: String(body.skill_triggered || body.skillTriggered || 'general'),
    tokensUsed: Number(body.tokens_used || body.tokensUsed || 0) || 0,
    responseTimeMs: Number(body.response_time_ms || body.responseTimeMs || 0) || 0,
    sourceCreatedAt,
    metadata: {
      transport: body.transport || 'telegram',
      roomId: body.room_id || body.roomId || null,
      threadId: body.thread_id || body.threadId || null,
      rawBodyKeys: Object.keys(body),
    },
  },
}];
